module.script:
import groovy.xml.XmlSlurper

// ---- Read XML from upstream (Scaler will pass file content; adapt as needed) ----
def xmlText = doc?.toString()
def root = new XmlSlurper(false,false).parseText(xmlText)

// ---- Extract fields (adjust XPaths to match your XML) ----
def phone   = root?.customer?.phone?.text()?.trim()
def consent = root?.customer?.smsConsent?.text()?.trim()?.toLowerCase() in ["true","yes","y","1"]
def msg     = root?.message?.text()?.trim()

// ---- Basic validation ----
if (!consent) throw new RuntimeException("SMS consent not granted")
if (!phone)   throw new RuntimeException("Missing phone number")
if (!phone.startsWith("+")) throw new RuntimeException("Phone must be in E.164 format (e.g., +19165551234)")
if (!msg)     throw new RuntimeException("Missing message body")

// ---- Build a context map for downstream modules ----
def ctx = [
  phone: phone,
  message: msg,
  correlationId: (root?.correlationId?.text() ?: UUID.randomUUID().toString()),
  customerId: (root?.customer?.id?.text() ?: ""),
  sourceFile: (root?.sourceFile?.text() ?: "")
]
return ctx

import java.net.HttpURLConnection import java.net.URL import java.net.URLEncoder
// ---- Pull parameters (Scaler may expose workflow params differently; adapt) ---- def API_URL = SMS_API_URL def AUTH = SMS_AUTH_HEADER def FROM = SMS_FROM_NUMBER
def toNumber = ctx.phone def messageText = ctx.message
// ---- Build x-www-form-urlencoded body (Twilio-style). For other providers, change body + headers. ---- def body = "To=" + URLEncoder.encode(toNumber, "UTF-8") + "&From="+ URLEncoder.encode(FROM, "UTF-8") + "&Body="+ URLEncoder.encode(messageText, "UTF-8")
URL url = new URL(API_URL) HttpURLConnection conn = (HttpURLConnection) url.openConnection() conn.setRequestMethod("POST") conn.setDoOutput(true) conn.setRequestProperty("Authorization", AUTH) conn.setRequestProperty("Content-Type", "application/x-www-form-urlencoded")
conn.outputStream.withCloseable { it.write(body.bytes) }
def code = conn.responseCode def responseText = "" try { responseText = conn.inputStream?.text } catch (Exception e) { responseText = conn.errorStream?.text ?: e.message }
def ok = (code >= 200 && code < 300)
return [ ok: ok, httpCode: code, providerResponse: responseText, correlationId: ctx.correlationId, phone: toNumber, customerId: ctx.customerId ]
